<section class="admin-page-head"><div><p class="eyebrow">BUN VENIT ÎN ATELIER</p><h1>Dashboard</h1></div><span><?= date('d F Y') ?></span></section><section class="kpi-grid"><article><small>Vânzări azi</small><strong><?= money($kpis['sales']) ?></strong><span>Comenzi confirmate</span></article><article><small>Comenzi azi</small><strong><?= (int)$kpis['orders'] ?></strong><span>Necesită atenție</span></article><article><small>Clienți noi</small><strong><?= (int)$kpis['customers'] ?></strong><span>Astăzi</span></article><article><small>Stoc redus</small><strong><?= (int)$kpis['low_stock'] ?></strong><span>Variante</span></article></section><section class="admin-dashboard-grid"><article class="admin-panel"><div class="panel-head"><h2>Vânzări - ultimele 12 zile</h2></div><div class="sales-chart"><?php $totals=array_map(fn($row)=>(int)$row['total'],$chart);$max=$totals?max(1,max($totals)):1;foreach($chart as $row): ?><div style="--bar:<?= max(6,(int)$row['total']/$max*100) ?>%"><span></span><small><?= date('d.m',strtotime($row['day'])) ?></small></div><?php endforeach; ?><?php if(!$chart): ?><div class="admin-empty">Graficul va apărea după prima comandă.</div><?php endif; ?></div></article><article class="admin-panel"><div class="panel-head"><h2>Notificări</h2><a href="<?= e(url('/admin/notificari')) ?>">Vezi toate</a></div><div class="admin-feed"><?php foreach($notifications as $item): ?><a href="<?= e(url($item['url']??'/admin/notificari')) ?>"><strong><?= e($item['title']) ?></strong><span><?= e($item['body']) ?></span></a><?php endforeach; ?><?php if(!$notifications): ?><div class="admin-empty">Nicio notificare.</div><?php endif; ?></div></article></section><section class="admin-panel"><div class="panel-head"><h2>Comenzi recente</h2><a href="<?= e(url('/admin/comenzi')) ?>">Toate comenzile</a></div><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Comandă</th><th>Client</th><th>Data</th><th>Status</th><th>Total</th></tr></thead><tbody><?php foreach($recent as $order): ?><tr><td><a href="<?= e(url('/admin/comenzi/'.$order['id'])) ?>"><strong><?= e($order['order_number']) ?></strong></a></td><td><?= e($order['email']) ?></td><td><?= date('d.m.Y H:i',strtotime($order['created_at'])) ?></td><td><span class="status-pill"><?= e($order['order_status']) ?></span></td><td><?= money($order['grand_total_minor']) ?></td></tr><?php endforeach; ?></tbody></table></div></section>
